import { getServerSession } from "next-auth";
import { authOptions } from "../lib/auth";
import { redirect } from "next/navigation";
import { prisma } from "../lib/prisma";
import Link from "next/link";

export default async function RecordsPage() {
  const session = await getServerSession(authOptions);
  
  // ตรวจสอบสิทธิ์การเข้าใช้งาน
  if (!session || !session.user?.email) redirect("/login");

  // ดึงข้อมูลบันทึกสุขภาพทั้งหมดของผู้ใช้งาน เรียงลำดับจากวันที่ล่าสุด
  const records = await prisma.healthRecord.findMany({
    where: {
      author: { user: session.user.email }
    },
    orderBy: { date: "desc" }
  });

  return (
    <section className="container" style={{ marginTop: '40px', paddingBottom: '50px' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: '24px' }}>ประวัติสุขภาพรายวัน</h1>
          <p className="muted" style={{ margin: '5px 0 0 0' }}>รายการบันทึกอาการ Office Syndrome ทั้งหมดของคุณ</p>
        </div>
        <Link href="/records/new" className="btn" style={{ background: '#0ea5e9', color: 'white', textDecoration: 'none' }}>
          เพิ่มบันทึกใหม่
        </Link>
      </header>

      {records.length === 0 ? (
        <div className="card" style={{ textAlign: 'center', padding: '50px' }}>
          <p className="muted">ยังไม่มีข้อมูลบันทึกในระบบ เริ่มต้นบันทึกอาการของคุณวันนี้</p>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          {records.map((record) => (
            <article key={record.id} className="card" style={{ padding: '20px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div>
                  <h3 style={{ margin: '0 0 10px 0', fontSize: '18px' }}>
                    วันที่: {new Date(record.date).toLocaleDateString('th-TH', { 
                      year: 'numeric', month: 'long', day: 'numeric' 
                    })}
                  </h3>
                  
                  {/* แสดงรายการอาการที่ตรวจพบ */}
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                    {record.headache && <span className="badge" style={{ background: '#fee2e2', color: '#b91c1c' }}>ปวดศีรษะ</span>}
                    {record.neckPain && <span className="badge" style={{ background: '#fee2e2', color: '#b91c1c' }}>ปวดคอ/บ่า</span>}
                    {record.backPain && <span className="badge" style={{ background: '#fee2e2', color: '#b91c1c' }}>ปวดหลัง</span>}
                    {record.eyeStrain && <span className="badge" style={{ background: '#fee2e2', color: '#b91c1c' }}>ตาล้า</span>}
                    {record.fingerNumbness && <span className="badge" style={{ background: '#fee2e2', color: '#b91c1c' }}>นิ้วล็อค</span>}
                    {record.wristPain && <span className="badge" style={{ background: '#fee2e2', color: '#b91c1c' }}>ปวดข้อมือ</span>}
                    {record.legNumbness && <span className="badge" style={{ background: '#fee2e2', color: '#b91c1c' }}>ขาชา</span>}
                    {record.tookBreaks && <span className="badge" style={{ background: '#d1fae5', color: '#047857' }}>ได้พักยืดเส้น</span>}
                  </div>
                </div>

                <div style={{ textAlign: 'right' }}>
                  <span style={{ fontSize: '14px', color: '#64748b' }}>ความเหนื่อยล้า</span>
                  <div style={{ fontSize: '20px', fontWeight: 'bold', color: '#0ea5e9' }}>{record.stressLevel} / 5</div>
                </div>
              </div>

              {record.note && (
                <div style={{ marginTop: '15px', padding: '10px', background: '#f8fafc', borderRadius: '6px', fontSize: '14px', color: '#475569' }}>
                  <strong>บันทึกเพิ่มเติม:</strong> {record.note}
                </div>
              )}
              
              <div style={{ marginTop: '15px', display: 'flex', gap: '10px', justifyContent: 'flex-end' }}>
                <Link href={`/records/${record.id}/edit`} style={{ fontSize: '14px', color: '#64748b', textDecoration: 'none' }}>แก้ไข</Link>
              </div>
            </article>
          ))}
        </div>
      )}
    </section>
  );
}