import { NextAuthOptions } from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";
import { prisma } from "./prisma";

export const authOptions: NextAuthOptions = {
  providers: [
    CredentialsProvider({
      name: "Credentials",
      credentials: {
        user: { label: "User", type: "text" },
        password: { label: "Password", type: "password" }
      },
      async authorize(credentials) {
        if (!credentials?.user || !credentials?.password) return null;

        const dbUser = await prisma.user.findUnique({
          where: { user: credentials.user }
        });

        if (dbUser && dbUser.password === credentials.password) {
          // ส่งค่า dbUser.user ไปที่ name เพื่อให้ระบบแสดงผลชื่อ User บนหน้าจอ
          return { id: dbUser.id, name: dbUser.user, email: dbUser.email };
        }
        return null;
      }
    })
  ],
  callbacks: {
    async session({ session, token }) {
      if (session.user) session.user.name = token.name;
      return session;
    },
    async jwt({ token, user }) {
      if (user) token.name = user.name;
      return token;
    }
  },
  session: { strategy: "jwt" },
  pages: { signIn: "/login" },
  secret: process.env.NEXTAUTH_SECRET,
};